        // Drain static queue to prevent cross-test interference
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    public void SendAndReceive_SingleNotification_RoundTripsCorrectly()
    {
        // Act
