        return dept;
    }

    private Course CreateCourse(int id = 1050, string title = "Chemistry", int? deptId = null)
    {
        if (deptId == null)
        {
            var dept = CreateDepartment();
            deptId = dept.DepartmentID;
        }
        var course = new Course
        {
            CourseID = id,
            Title = title,
            Credits = 3,
            DepartmentID = deptId.Value
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
