namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        // Drain the static notification queue
        while (_controller.GetNotifications() is JsonResult jr
            && jr.Value is not null)
        {
            // Extract the dynamic count property
            var val = jr.Value;
            var countProp = val.GetType().GetProperty("count");
            if (countProp != null)
            {
                var count = (int)countProp.GetValue(val)!;
                if (count == 0) break;
            }
            else break;
        }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void GetNotifications_WhenEmpty_ReturnsSuccessWithZeroCount()
    {
        var result = _controller.GetNotifications();

        Assert.IsNotNull(result);
        var val = result.Value;
        Assert.IsNotNull(val);

        var successProp = val.GetType().GetProperty("success");
        Assert.IsTrue((bool)successProp!.GetValue(val)!);

        var countProp = val.GetType().GetProperty("count");
        Assert.AreEqual(0, (int)countProp!.GetValue(val)!);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsNotNull(result);
        var val = result.Value;
        Assert.IsNotNull(val);

        var successProp = val.GetType().GetProperty("success");
        Assert.IsTrue((bool)successProp!.GetValue(val)!);
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.IsNotNull(result);
    }
}
