using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new DepartmentsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Department CreateDepartment(string name = "Engineering", decimal budget = 350000)
    {
        var dept = new Department
        {
            Name = name,
            Budget = budget,
            StartDate = new DateTime(2023, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Instructor CreateInstructor(string first = "John", string last = "Doe")
    {
        var instructor = new Instructor
        {
            FirstMidName = first,
            LastName = last,
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    // ── Index ──

    [TestMethod]
    public void Index_ReturnsViewWithDepartments()
    {
        CreateDepartment("Math");
        CreateDepartment("Science");

        var result = _controller.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    // ── Details ──

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var dept = CreateDepartment();

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(dept.DepartmentID, (result.Model as Department)!.DepartmentID);
    }

    // ── Create GET ──

    [TestMethod]
    public void Create_Get_ReturnsView()
    {
        CreateInstructor();

        var result = _controller.Create() as ViewResult;

        Assert.IsNotNull(result);
    }

    // ── Create POST ──

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = new Department
        {
            Name = "New Dept",
            Budget = 50000,
            StartDate = new DateTime(2023, 1, 1)
        };

        var result = _controller.Create(dept) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, _context.Departments.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        CreateInstructor();
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department { Name = "" };

        var result = _controller.Create(dept) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(0, _context.Departments.Count());
    }

    // ── Edit GET ──

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = CreateDepartment();
        CreateInstructor();

        var result = _controller.Edit((int?)dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(dept.DepartmentID, (result.Model as Department)!.DepartmentID);
    }

    // ── Edit POST ──

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = CreateDepartment();
        CreateInstructor();
        _context.Entry(dept).State = EntityState.Detached;

        var updated = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated",
            Budget = 100000,
            StartDate = new DateTime(2023, 6, 1)
        };

        var result = _controller.Edit(updated) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        CreateInstructor();
        _controller.ModelState.AddModelError("Name", "Required");

        var dept = new Department
        {
            DepartmentID = 1,
            Name = "",
            Budget = 0,
            StartDate = DateTime.Now
        };

        var result = _controller.Edit(dept) as ViewResult;

        Assert.IsNotNull(result);
    }

    // ── Delete GET ──

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = CreateDepartment();

        var result = _controller.Delete(dept.DepartmentID) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual(dept.DepartmentID, (result.Model as Department)!.DepartmentID);
    }

    // ── Delete POST ──

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var dept = CreateDepartment();

        var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(0, _context.Departments.Count());
    }
}

