using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void About_ReturnsViewWithEnrollmentGroups()
    {
        // Arrange — two students with same date, one with different
        _context.Students.Add(new Student { FirstMidName = "A", LastName = "One", EnrollmentDate = new DateTime(2023, 9, 1) });
        _context.Students.Add(new Student { FirstMidName = "B", LastName = "Two", EnrollmentDate = new DateTime(2023, 9, 1) });
        _context.Students.Add(new Student { FirstMidName = "C", LastName = "Three", EnrollmentDate = new DateTime(2024, 1, 15) });
        _context.SaveChanges();

        var result = _controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var sept2023 = model.First(g => g.EnrollmentDate == new DateTime(2023, 9, 1));
        Assert.AreEqual(2, sept2023.StudentCount);

        var jan2024 = model.First(g => g.EnrollmentDate == new DateTime(2024, 1, 15));
        Assert.AreEqual(1, jan2024.StudentCount);
    }

    [TestMethod]
    public void About_NoStudents_ReturnsEmptyList()
    {
        var result = _controller.About() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void Contact_ReturnsViewWithMessage()
    {
        var result = _controller.Contact() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsView()
    {
        var result = _controller.Error() as ViewResult;
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewWithMessage()
    {
        var result = _controller.Unauthorized() as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }
}

