namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _controller = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new InstructorsController(_context);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Instructor CreateInstructor(string first = "Kim", string last = "Abercrombie")
    {
        var instructor = new Instructor
        {
            FirstMidName = first,
            LastName = last,
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Department CreateDepartment(string name = "Engineering")
    {
        var dept = new Department
        {
            Name = name,
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Course CreateCourse(int id, string title, int deptId)
    {
        var course = new Course
        {
            CourseID = id,
            Title = title,
            Credits = 3,
            DepartmentID = deptId,
            Enrollments = new List<Enrollment>()
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    // ── Index ──

    [TestMethod]
    public void Index_NoParams_ReturnsAllInstructors()
    {
        CreateInstructor("Kim", "Abercrombie");
        CreateInstructor("Fadi", "Fakhouri");

        var result = _controller.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_ShowsCourses()
    {
        var dept = CreateDepartment();
        var instructor = CreateInstructor();
        var course = CreateCourse(100, "Chemistry", dept.DepartmentID);
        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID });
        _context.SaveChanges();

        var result = _controller.Index(instructor.ID, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as ContosoUniversity.Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(1, model.Courses.Count());
    }

    // ── Details ──

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
