using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _controller = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;
    private string _tempDir = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _loggerMock = new Mock<ILogger<CoursesController>>();

        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempDir);
        _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);

        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
        _controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
    }

    [TestCleanup]
    public void Cleanup()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempDir))
            Directory.Delete(_tempDir, recursive: true);
    }

    private Department CreateDepartment(string name = "Engineering")
    {
        var dept = new Department { Name = name, Budget = 100000, StartDate = DateTime.Now };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Course CreateCourse(int id = 1050, string title = "Chemistry", int? deptId = null)
    {
        if (deptId == null)
        {
            var dept = CreateDepartment();
            deptId = dept.DepartmentID;
        }
        var course = new Course
        {
            CourseID = id,
            Title = title,
            Credits = 3,
            DepartmentID = deptId.Value
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
